$changelogPath = Join-Path (Get-Location) "CHANGELOG.md"; $changelogContent = Get-Content $changelogPath -Raw; $parts = $changelogContent -split "(?m)^## \["; $numToTake = [Math]::Min(16, $parts.Length); $extracted = $parts[0]; for ($i = 1; $i -lt $numToTake; $i++) { $extracted += "## [" + $parts[$i] }; $resourcePath = Join-Path (Get-Location) "Resources\about-changelog.txt"; $utf8NoBom = New-Object System.Text.UTF8Encoding $false; [System.IO.File]::WriteAllText($resourcePath, $extracted.Trim(), $utf8NoBom);
